"use client"

import { useRef, useState } from "react"
import { motion, useInView } from "framer-motion"
import { processSteps } from "@/lib/data"
import { ArrowRight, ArrowLeft } from "lucide-react"
import { Swiper as SwiperClass } from 'swiper/types'
import { Swiper, SwiperSlide } from 'swiper/react'
import 'swiper/css'
import { Magnetic } from "@/components/ui/Magnetic"

export default function Process() {
  const swiperRef = useRef<SwiperClass | null>(null)
  const headerRef = useRef(null)
  const isHeaderInView = useInView(headerRef, { once: true, amount: 0.5 })

  return (
    <section id="process" className="py-24 bg-background overflow-hidden relative border-y border-border/30">
      <div className="max-w-7xl mx-auto px-6 md:px-10 lg:px-20 mb-12 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div ref={headerRef}>
          <motion.p 
            initial={{ opacity: 0, y: 20 }}
            animate={isHeaderInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
            className="text-xs font-sans font-semibold uppercase tracking-label text-accent mb-4"
          >
            How We Engage
          </motion.p>
          <motion.h2 
            initial={{ opacity: 0, y: 20 }}
            animate={isHeaderInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
            transition={{ delay: 0.1 }}
            className="font-syne text-4xl md:text-5xl lg:text-6xl font-bold tracking-heading text-foreground"
          >
            Process Architecture
          </motion.h2>
        </div>
        
        {/* Navigation Controls */}
        <div className="hidden md:flex gap-4">
          <Magnetic>
            <button 
              onClick={() => swiperRef.current?.slidePrev()}
              className="w-14 h-14 rounded-full border border-border flex items-center justify-center hover:bg-white/5 transition-colors focus:ring-2 focus:ring-accent outline-none"
              aria-label="Previous step"
            >
              <ArrowLeft className="w-5 h-5 text-foreground" />
            </button>
          </Magnetic>
          <Magnetic>
            <button 
              onClick={() => swiperRef.current?.slideNext()}
              className="w-14 h-14 rounded-full border border-border flex items-center justify-center hover:bg-white/5 transition-colors focus:ring-2 focus:ring-accent outline-none"
              aria-label="Next step"
            >
              <ArrowRight className="w-5 h-5 text-foreground" />
            </button>
          </Magnetic>
        </div>
      </div>

      <div className="pl-6 md:pl-10 lg:pl-20 cursor-grab active:cursor-grabbing w-full pb-10">
        <Swiper
          onSwiper={(swiper) => (swiperRef.current = swiper)}
          slidesPerView={1.2}
          spaceBetween={24}
          breakpoints={{
            640: { slidesPerView: 2.2 },
            1024: { slidesPerView: 3.2 },
          }}
          className="!overflow-visible"
        >
          {processSteps.map((step, i) => (
            <SwiperSlide key={i} className="h-auto">
              <div className="h-full group relative bg-card/40 backdrop-blur-md border border-border rounded-2xl p-8 md:p-10 hover:border-accent/50 hover:bg-card/60 transition-all duration-300">
                <span className="font-syne text-6xl font-bold text-transparent [-webkit-text-stroke:1px_rgba(255,255,255,0.15)] group-hover:[-webkit-text-stroke:1px_rgba(200,146,10,0.5)] group-hover:opacity-100 group-hover:text-transparent transition-all duration-500 block mb-6">
                  {step.number}
                </span>
                <h3 className="font-syne text-2xl font-bold text-foreground mb-4">
                  {step.title}
                </h3>
                <p className="font-sans text-sm text-muted-foreground leading-relaxed">
                  {step.description}
                </p>
                {/* Visual process chain line */}
                {i !== processSteps.length - 1 && (
                   <div className="hidden md:block absolute top-[20%] right-[-24px] w-6 h-px bg-border group-hover:bg-accent transition-colors" />
                )}
              </div>
            </SwiperSlide>
          ))}
        </Swiper>
      </div>
    </section>
  )
}
