"use client"

import { KineticText } from '@/components/ui/KineticText'
import { motion, useScroll, useTransform } from 'framer-motion'
import { ArrowRight, ChevronDown } from 'lucide-react'
import dynamic from 'next/dynamic'
import Link from 'next/link'
import { useRef } from 'react'

const HeroCanvas = dynamic(() => import('@/components/ui/HeroCanvas').then(mod => mod.HeroCanvas), { ssr: false })
const OrganicHighlight = dynamic(() => import('@/components/ui/OrganicHighlight').then(mod => mod.OrganicHighlight))

const heroVariants = {
  hidden: { opacity: 0, y: 24 },
  visible: (i: number) => ({
    opacity: 1,
    y: 0,
    transition: {
      delay: i * 0.15,
      duration: 0.6,
      ease: [0.25, 0.1, 0.25, 1],
    },
  }),
}

export default function Hero() {
  const sectionRef = useRef(null)
  const { scrollYProgress } = useScroll({
    target: sectionRef,
    offset: ['start start', 'end start'],
  })
  const illustrationY = useTransform(scrollYProgress, [0, 1], [0, -40])
  const textY = useTransform(scrollYProgress, [0, 1], [0, -15])
  const scrollIndicatorOpacity = useTransform(scrollYProgress, [0, 0.15], [1, 0])

  return (
    <section ref={sectionRef} className="gradient-hero-subtle noise-overlay min-h-[85dvh] md:min-h-[100dvh] flex items-center relative overflow-hidden">
      <HeroCanvas />

      <div className="relative z-10 max-w-7xl mx-auto px-6 md:px-10 lg:px-20 py-20 md:py-32 lg:py-40 w-full">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-16 items-center">
          {/* Left column */}
          <motion.div style={{ y: textY }}>
            <motion.p
              custom={0}
              initial="hidden"
              animate="visible"
              variants={heroVariants}
              className="text-[10px] md:text-xs font-sans font-semibold uppercase tracking-[0.2em] md:tracking-[0.3em] text-accent mb-8"
            >
              Strategy · Engineering · Intelligence
            </motion.p>

            <KineticText 
              as="h1" 
              className="font-syne text-[28px] sm:text-4xl md:text-6xl lg:text-7xl xl:text-[5.5rem] text-foreground leading-[1.08] tracking-heading font-bold"
            >
              Architecting Strategy.
            </KineticText>
            <h1 className="font-syne text-[28px] sm:text-4xl md:text-6xl lg:text-7xl xl:text-[5.5rem] text-foreground leading-[1.08] tracking-heading font-bold mt-2">
              Engineering the <OrganicHighlight>Future.</OrganicHighlight>
            </h1>

            <motion.p
              custom={2}
              initial="hidden"
              animate="visible"
              variants={heroVariants}
              className="font-sans text-base md:text-xl text-text-secondary max-w-xl mt-8 leading-relaxed"
            >
              beehoop is an end-to-end strategic and engineering partner. From boardroom advisory and financial modelling to data pipelines, bespoke software, and intelligent dashboards — we don&apos;t just advise. We architect, engineer, and deliver.
            </motion.p>

            <motion.div
              custom={3}
              initial="hidden"
              animate="visible"
              variants={heroVariants}
              className="mt-12 flex flex-col sm:flex-row items-start sm:items-center gap-6"
            >
              <Link
                href="/contact"
                className="bg-accent-light text-[#090a0c] font-sans font-semibold px-8 py-4 rounded-full hover:bg-accent-hover hover:scale-[1.02] hover:shadow-lg transition-all duration-300 text-sm"
              >
                Start a conversation
              </Link>
              <Link
                href="/cases"
                className="font-sans text-sm font-medium text-text-primary flex items-center gap-2 hover:gap-3 transition-all group"
              >
                See our work
                <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
              </Link>
            </motion.div>
          </motion.div>

          {/* Right column empty (Canvas acts as backdrop) */}
          <div className="hidden lg:flex justify-center items-center w-full max-w-[480px] mx-auto opacity-0" aria-hidden="true">
            {/* Spacer for structural balance */}
          </div>
        </div>
      </div>

      {/* Scroll indicator — fades on scroll */}
      <motion.div
        style={{ opacity: scrollIndicatorOpacity }}
        className="absolute bottom-8 left-1/2 -translate-x-1/2 z-10"
      >
        <ChevronDown className="w-5 h-5 text-text-muted animate-bounce-gentle" />
      </motion.div>
    </section>
  )
}
